import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import Api from "../api/Api";

function Admin() {
  const [users, setUsers] = useState([]);
  const [scheduleMap, setScheduleMap] = useState({});
  const [editingSchedule, setEditingSchedule] = useState({});
  const [showRequests, setShowRequests] = useState(false);
  const [statusFilter, setStatusFilter] = useState("All");
  const [requests, setRequests] = useState([]);
  const [orderMap, setOrderMap] = useState({});
  const [isSorted, setIsSorted] = useState(false);


  const [locations, setLocations] = useState([]);
const [supervisors, setSupervisors] = useState([]);

const [selectedSupervisor, setSelectedSupervisor] =
  useState("");

const [selectedLocations, setSelectedLocations] =
  useState([]);
  // ================= USERS =================
  const fetchUsers = async () => {
    try {
      const res = await axios.get(Api.get_All_User);
      setUsers(res.data || []);

const onlySupervisors =
  res.data.filter(
    (u) => u.role === "supervisor"
  );

setSupervisors(onlySupervisors);
    } catch (err) {
      console.log(err);
    }
  };



  const fetchLocations = async () => {
  try {
    const res = await axios.get(
      Api.get_All_Locations
    );

    setLocations(res.data);

  } catch (err) {
    console.log(err);
  }
};
  // ================= REQUESTS =================
  const fetchRequests = async () => {
    try {
      const res = await axios.get(Api.get_All_Emg_Req);

      console.log("RAW RESPONSE:", res.data);

      const data =
        res.data?.data ||
        res.data?.requests ||
        res.data ||
        [];

      setRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log("FETCH ERROR:", err);
      setRequests([]);
    }
  };
useEffect(() => {
  fetchUsers();
  fetchLocations();
}, []);



const assignLocations = async () => {
  try {

    await axios.put(
      Api.assign_Supervisor,
      {
        supervisorId:
          selectedSupervisor,

        locationIds:
          selectedLocations,
      }
    );

    alert("Locations Assigned");

  } catch (err) {
    console.log(err);
  }
};

  // ================= ASSIGN ORDER (LIVE UI UPDATE) =================
  const handleAssignOrder = async (id) => {
    try {
      const order = orderMap[id];

      if (order === undefined || order === "") {
        return alert("Enter order first");
      }

      const numOrder = Number(order);

      // đź”Ą UI UPDATE FIRST
      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? { ...req, scheduleOrder: numOrder }
            : req
        )
      );

      // đź”Ą API CALL (CORRECT)
      const res = await axios.put(
        `${Api.update_Emg_Order}/${id}`,
        {
          scheduleOrder: numOrder,
        }
      );

      console.log("UPDATE RESPONSE:", res.data);

      setOrderMap({});
      setIsSorted(false);

    } catch (err) {
      console.log("ASSIGN ERROR:", err.response || err);
      alert("Assign failed");
    }
  };

  // ================= UPDATE ORDER =================
  const handleUpdateAssign = async (id) => {
    try {
      const order = orderMap[id];

      if (!order && order !== 0) {
        return alert("Enter order first");
      }

      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? { ...req, scheduleOrder: Number(order) }
            : req
        )
      );

      await axios.put(
        `${Api.update_Emg_Order}/${id}`,
        {
          scheduleOrder: Number(order),
        }
      );

      setOrderMap({});
      setIsSorted(false);

    } catch (err) {
      console.log(err);
    }
  };

  // ================= FINAL SORT =================
  const filteredRequests = requests.filter((req) => {
    if (statusFilter === "All") {
      return req.status !== "Completed";
    }

    return req.status === statusFilter;
  });


  const handleSchedule = async (id) => {
    try {
      const data = scheduleMap[id];

      if (!data?.date || !data?.time) {
        return alert("Select Date & Time");
      }

      await axios.put(`${Api.update_Emg_Order}/${id}`, {
        scheduledDate: data.date,
        scheduledTime: data.time,
        status: "Scheduled",
      });

      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? {
              ...req,
              scheduledDate: data.date,
              scheduledTime: data.time,
              status: "Scheduled",
            }
            : req
        )
      );

      setEditingSchedule((prev) => ({
        ...prev,
        [id]: false,
      }));

      setScheduleMap((prev) => ({
        ...prev,
        [id]: {},
      }));

      alert("Schedule Updated Successfully");
    } catch (error) {
      console.log(error);
      alert("Schedule Failed");
    }
  };

  useEffect(() => {
  fetchRequests();
}, []);

  const displayedRequests = [...filteredRequests].sort((a, b) => {
  const priorityRank = {
    High: 1,
    Medium: 2,
    Low: 3,
  };

  return (
    priorityRank[a.priority] -
    priorityRank[b.priority]
  );
});

  const renderRequestCard = (req) => (
  <div
    key={req._id}
    className="bg-white rounded-2xl border border-[#d6ddd2] p-6 hover:shadow-lg transition"
  >
    <div className="flex justify-between items-start">
      <div>
        <p className="text-xs uppercase tracking-wider text-gray-500">
          Request #{req._id.slice(-5)}
        </p>

        <h3 className="font-bold text-lg mt-1">
          {req.location?.name || "Location"}
        </h3>
      </div>

      <span
        className={`px-3 py-1 rounded-full text-xs font-semibold ${
          req.priority === "High"
            ? "bg-red-100 text-red-700"
            : req.priority === "Medium"
            ? "bg-yellow-100 text-yellow-700"
            : "bg-green-100 text-green-700"
        }`}
      >
        {req.priority}
      </span>
    </div>

    <div className="mt-4 space-y-2 text-sm">
      <p>
        <strong>Status:</strong> {req.status}
      </p>

      <p>
        <strong>Order:</strong>{" "}
        {req.scheduleOrder ?? "Not Assigned"}
      </p>

      {req.scheduledDate && (
        <p>
          <strong>Date:</strong> {req.scheduledDate}
        </p>
      )}

      {req.scheduledTime && (
        <p>
          <strong>Time:</strong> {req.scheduledTime}
        </p>
      )}
    </div>

    <div className="mt-4">
      <input
        type="number"
        placeholder="Order"
        value={orderMap[req._id] || ""}
        onChange={(e) =>
          setOrderMap({
            ...orderMap,
            [req._id]: e.target.value,
          })
        }
        className="border p-2 rounded w-full"
      />
    </div>

    <div className="mt-3 flex gap-2">
      <button
        onClick={() => handleAssignOrder(req._id)}
        className="bg-green-700 text-white px-4 py-2 rounded"
      >
        Assign
      </button>

      <button
        onClick={() => handleUpdateAssign(req._id)}
        className="bg-blue-700 text-white px-4 py-2 rounded"
      >
        Update
      </button>
    </div>

    <div className="mt-4">
      <button
        onClick={() =>
          setEditingSchedule((prev) => ({
            ...prev,
            [req._id]: !prev[req._id],
          }))
        }
        className="bg-orange-500 text-white px-4 py-2 rounded w-full"
      >
        Schedule
      </button>
    </div>

    {editingSchedule[req._id] && (
      <div className="mt-4 space-y-2">
        <input
          type="date"
          onChange={(e) =>
            setScheduleMap({
              ...scheduleMap,
              [req._id]: {
                ...scheduleMap[req._id],
                date: e.target.value,
              },
            })
          }
          className="border p-2 rounded w-full"
        />

        <input
          type="time"
          onChange={(e) =>
            setScheduleMap({
              ...scheduleMap,
              [req._id]: {
                ...scheduleMap[req._id],
                time: e.target.value,
              },
            })
          }
          className="border p-2 rounded w-full"
        />

        <button
          onClick={() => handleSchedule(req._id)}
          className="bg-green-600 text-white px-4 py-2 rounded w-full"
        >
          Save Schedule
        </button>
      </div>
    )}
  </div>
);


  return (
    <div className="min-h-screen bg-[#4CBB17]/20">

      <div >

        {/* HEADER */}
        {/* HEADER */}
        <div className="mb-8 bg-[#4CBB17]/40 px-6 ">
          <div className="flex items-center justify-between">

            {/* Logo + Title */}
            <div >
              <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
                <img
                  src="garbageVehicle.jpeg"
                  alt=""
                  className="w-16 h-16 object-contain"
                />
                CleanTrack
              </h1>

              <p className="text-gray-900 p-2">
                Smart Waste Management Control Center
              </p>
            </div>

            {/* Navigation Links */}
            <div className="flex items-center gap-8 text-lg font-semibold">

              <Link
                to="/create-account"
                className="text-green-900 hover:text-white-900 transition-all duration-300 hover:scale-105"
              >
                Create User
              </Link>

              <button
                onClick={() => {
                  setShowRequests(!showRequests);
                  fetchRequests();
                }}
                className="text-green-900 hover:text-green-900 transition-all duration-300 hover:scale-105"
              >
                View Requests
              </button>

              <Link
  to="/create-location"
  className="text-green-900 hover:scale-105 transition"
>
  Create Locations
</Link>

             <Link
  to="/assign-location"
  className="text-green-900 hover:scale-105 transition"
>
  Assign Location
</Link>


            </div>
          </div>
        </div>

        <div className="text-center mb-10">
        <h1 className="text-5xl font-extrabold text-black-900">
          Admin Dashboard
        </h1>
      </div>

        {/* USERS */}
        <div className="bg-white rounded-2xl shadow-sm border border-[#d6ddd2] p-6 mb-8 m-8">

          <div className="flex justify-between items-center mb-6">

            <h2 className="text-2xl font-bold text-green-900">
              User Management
            </h2>

            <span className="bg-green-100 text-green-800 px-4 py-2 rounded-full text-sm font-semibold">
              {users.length} Users
            </span>

          </div>

          <div className="overflow-x-auto">

            <table className="w-full">

              <thead>
                <tr className="bg-green-900 text-white">
                  <th className="p-4 text-left">Name</th>
                  <th className="p-4 text-left">Mobile</th>
                  <th className="p-4 text-left">Role</th>
                </tr>
              </thead>

              <tbody>
                {users.map((user) => (
                  <tr
                    key={user._id}
                    className="border-b hover:bg-green-50 transition"
                  >
                    <td className="p-4 font-medium">
                      {user.name}
                    </td>

                    <td className="p-4">
                      {user.mobile}
                    </td>

                    <td className="p-4">
                      <span className="bg-green-100 text-green-800 px-3 py-1 rounded-full text-sm font-medium">
                        {user.role}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>

            </table>

          </div>

        </div>




        {/* REQUESTS */}
        {showRequests && (
          <div>

            <div className="flex justify-between items-center mb-6 m-8">

              <div>
                <h2 className="text-3xl font-bold text-green-900">
                  Active Requests
                </h2>

                <p className="text-gray-500 text-sm">
                  Pickup Scheduling & Monitoring
                </p>
              </div>

              <div className="flex items-center gap-3">

                <select
                  value={statusFilter}
                  onChange={(e) =>
                    setStatusFilter(e.target.value)
                  }
                  className="border border-gray-300 rounded-lg px-4 py-2 bg-white"
                >
                  <option value="All">All Active</option>
                  <option value="Pending">Pending</option>
                  <option value="Scheduled">Scheduled</option>
                  <option value="Arrived">Arrived</option>
                  <option value="Completed">Completed</option>
                </select>

                <div className="bg-white border border-[#d6ddd2] px-5 py-3 rounded-xl">
                  <span className="font-semibold">
                    Total Requests:
                  </span>{" "}
                  {displayedRequests.length}
                </div>

              </div>

            </div>

            {displayedRequests.length === 0 ? (

              <div className="bg-white rounded-2xl shadow-sm border border-[#d6ddd2] p-10 text-center">
                No requests found
              </div>

            ) : (

              <div className="grid lg:grid-cols-2 xl:grid-cols-4 gap-6">

                {displayedRequests.map((req) => (

                  <div
                    key={req._id}
                    className="bg-white rounded-2xl border border-[#d6ddd2] p-6 hover:shadow-lg transition m-8"
                  >

                    {/* TOP */}
                    <div className="flex justify-between items-start">

                      <div>

                        <p className="text-xs uppercase tracking-wider text-gray-500">
                          Request #{req._id.slice(-5)}
                        </p>

                        <h3 className="text-xl font-bold text-green-900 mt-1">
                         đź“Ť {req.location?.locationName}
                        </h3>

                      </div>

                      <span
                        className={
                          req.status === "Completed"
                            ? "bg-green-500 text-white px-4 py-1 rounded-full"
                            : req.status === "Scheduled"
                              ? "bg-sky-500 text-white px-4 py-1 rounded-full"
                              : req.status === "Pending"
                                ? "bg-yellow-500 text-black px-4 py-1 rounded-full"
                                : req.status === "Arrived"
                                  ? "bg-orange-500 text-white px-4 py-1 rounded-full"
                                  : "bg-gray-500 text-white px-4 py-1 rounded-full"
                        }
                      >
                        {req.status}
                      </span>


                    </div>

                    {/* INFO */}
                    <div className="mt-5 space-y-2">

                      <p>
                        <span className="font-semibold">
                          Priority:
                        </span>{" "}
                        {req.priority}
                      </p>

                      <p className="text-sm text-gray-500 mt-4">Created:
                        {new Date(req.createdAt).toLocaleString("en-IN", {
                          day: "2-digit",
                          month: "short",
                          year: "numeric",
                          hour: "2-digit",
                          minute: "2-digit",
                          hour12: true,
                        })}
                      </p>



                    </div>
                    {/* Timeline Details */}

<div className="mt-4 space-y-2 border-t pt-3">



 

  {req.arrivedAt && (
    <p className="text-sm text-yellow-700 font-medium">
      Arrived:
      {" "}
      {new Date(req.arrivedAt).toLocaleString("en-IN", {
        day: "2-digit",
        month: "short",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        hour12: true,
      })}
    </p>
  )}

  {req.completedAt && (
    <p className="text-sm text-green-700 font-medium">
       Completed:
      {" "}
      {new Date(req.completedAt).toLocaleString("en-IN", {
        day: "2-digit",
        month: "short",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        hour12: true,
      })}
    </p>
  )}

</div>

                    {/* SCHEDULE SECTION */}
{/* SCHEDULE SECTION */}


  {req.status === "Pending" && !editingSchedule[req._id] && (
    <>
      <button
        onClick={() =>
          setEditingSchedule((prev) => ({
            ...prev,
            [req._id]: true,
          }))
        }
        className="w-full bg-green-700 hover:bg-green-800 text-white py-2 rounded-xl font-semibold"
      >
        Schedule Pickup
      </button>
    </>
  )}

  {req.status === "Scheduled" && !editingSchedule[req._id] && (
    <>
      <div className="bg-sky-50 p-3 rounded-lg mb-3">
        <p className="text-sm text-sky-700 font-medium">
          Scheduled:
          {" "}
          {new Date(req.scheduledDate).toLocaleDateString("en-IN", {
            day: "2-digit",
            month: "short",
            year: "numeric",
          })}
          {" | "}
          {req.scheduledTime}
        </p>
      </div>

      <button
        onClick={() =>
          setEditingSchedule((prev) => ({
            ...prev,
            [req._id]: true,
          }))
        }
        className="w-full bg-yellow-500 hover:bg-yellow-600 text-white py-2 rounded-xl font-semibold"
      >
        Update Schedule
      </button>
    </>
  )}

 {editingSchedule[req._id] && (
  <div className="space-y-3">

    <input
      type="date"
      className="w-full border border-gray-300 rounded-lg p-2"
      value={scheduleMap[req._id]?.date || ""}
      onChange={(e) =>
        setScheduleMap((prev) => ({
          ...prev,
          [req._id]: {
            ...prev[req._id],
            date: e.target.value,
          },
        }))
      }
    />

    <input
      type="time"
      className="w-full border border-gray-300 rounded-lg p-2"
      value={scheduleMap[req._id]?.time || ""}
      onChange={(e) =>
        setScheduleMap((prev) => ({
          ...prev,
          [req._id]: {
            ...prev[req._id],
            time: e.target.value,
          },
        }))
      }
    />

    <button
      onClick={() => handleSchedule(req._id)}
      className="w-full bg-green-900 hover:bg-green-800 text-white py-2 rounded-xl font-semibold"
    >
      {req.status === "Scheduled"
        ? "Save Update"
        : "Schedule"}
    </button>

    <button
      onClick={() =>
        setEditingSchedule((prev) => ({
          ...prev,
          [req._id]: false,
        }))
      }
      className="w-full bg-gray-400 hover:bg-gray-500 text-white py-2 rounded-xl font-semibold"
    >
      Cancel
    </button>

  </div>
)}

</div>
                 



                
                ))}

              </div>

            )}

          </div>
        )}

      </div>

    </div>
  );
}

export default Admin
